const discordData = $('When Executed by Another Workflow').item.json;

// Get total monthly income from Discord Input
const monthlyIncome = parseFloat(
  discordData.body.data.options.find(o => o.name === 'amount_in_php')?.value
);

if (!monthlyIncome || isNaN(monthlyIncome)) {
  throw new Error('Could not parse amount_in_php from Discord input.');
}

// Only ₱50,000 is declared as salary; the rest is allowance (not subject to contributions/tax)
const declaredSalary = 50000;
const allowance = Math.max(monthlyIncome - declaredSalary, 0);

// SSS 2025/2026: 15% rate, MSC floor ₱5,000 ceiling ₱35,000 — based on declared salary
const msc = Math.min(Math.max(declaredSalary, 5000), 35000);
const sss = Math.round(msc * 0.15);

// PhilHealth 2025/2026: 5% rate, floor ₱500 ceiling ₱5,000 — based on declared salary
const philhealth = Math.min(Math.max(declaredSalary * 0.05, 500), 5000);

// Pag-IBIG: fixed ₱200 for income above ₱5,000
const pagibig = 200;

// BIR Tax (TRAIN Law) — based on declared salary only
const annualDeclared = declaredSalary * 12;

// 8% Flat Rate (₱250k deduction for self-employed/professionals)
const taxableAnnual8 = Math.max(annualDeclared - 250000, 0);
const monthlyTax8pct = (taxableAnnual8 * 0.08) / 12;

// Graduated Rate (2023-2026 table)
function graduatedTax(annual) {
  if (annual <= 250000) return 0;
  if (annual <= 400000) return (annual - 250000) * 0.15;
  if (annual <= 800000) return 22500 + (annual - 400000) * 0.20;
  if (annual <= 2000000) return 102500 + (annual - 800000) * 0.25;
  if (annual <= 8000000) return 402500 + (annual - 2000000) * 0.30;
  return 2202500 + (annual - 8000000) * 0.35;
}
const monthlyTaxGrad = graduatedTax(annualDeclared) / 12;

// Quarterly BIR set-aside (3 months)
const quarterlyTax8 = monthlyTax8pct * 3;
const quarterlyTaxGrad = monthlyTaxGrad * 3;

// Take-home: total income minus contributions (computed on declared salary)
const takeHome8 = monthlyIncome - (sss + philhealth + pagibig + monthlyTax8pct);
const takeHomeGrad = monthlyIncome - (sss + philhealth + pagibig + monthlyTaxGrad);

const fmt = (n) => '₱' + Math.round(n).toLocaleString('en-PH');

const message = [
  `👽 I have computed your government obligations, **${discordData.body.member.user.global_name}**! My alien tax algorithms are flawless.`,
  ``,
  `💰 **Total Monthly Income:** ${fmt(monthlyIncome)}`,
  `> 📝 Declared Salary: ${fmt(declaredSalary)} | Allowance: ${fmt(allowance)}`,
  `> *(Contributions & BIR tax are computed on declared salary only)*`,
  ``,
  `**📋 Monthly Government Contributions (on ${fmt(declaredSalary)} salary):**`,
  `> 🔵 SSS: ${fmt(sss)} *(15% rate, MSC: ${fmt(msc)})*`,
  `> 🟢 PhilHealth: ${fmt(philhealth)} *(5% rate)*`,
  `> 🟡 Pag-IBIG: ${fmt(pagibig)}`,
  ``,
  `**🧾 BIR Income Tax (monthly set-aside):**`,
  `> 8% Flat Rate: **${fmt(monthlyTax8pct)}** ← *simpler, recommended*`,
  `> Graduated Rate: ${fmt(monthlyTaxGrad)}`,
  ``,
  `**🏠 Estimated Take-Home (from total income):**`,
  `> If 8% flat: **${fmt(takeHome8)}**`,
  `> If graduated: **${fmt(takeHomeGrad)}**`,
  ``,
  `**📅 Quarterly BIR Tax Reminder:**`,
  `> BIR income tax is **not paid monthly** — you file and pay 4x a year.`,
  `> 🗓️ Q1 Jan–Mar → due **May 15** | Q2 Apr–Jun → due **Aug 15** | Q3 Jul–Sep → due **Nov 15**`,
  `> 🗓️ Annual ITR (1701A) → due **April 15** of the following year`,
  `> 💸 Set aside per quarter → 8% flat: **${fmt(quarterlyTax8)}** | Graduated: ${fmt(quarterlyTaxGrad)}`,
  `> *(Each quarter you pay based on your cumulative income so far that year, minus prior payments)*`,
  ``,
  `⚠️ *SSS max MSC is ₱35,000 for 2025–2026. Confirm salary/allowance arrangement with your employer.*`,
  ``,
  `💡 *Use /log_tax to record this computation to the spreadsheet.*`
].join('\n');

return [{
  json: {
    message,
    token: discordData.body.token,
    applicationId: discordData.body.application_id
  }
}];

